{
  "name": "PreCalc Pro: California Edition",
  "description": "A comprehensive precalculus tutor app aligned with Larson 2007 and California Common Core State Standards, featuring AI tutoring, semester mapping, and Excel modeling labs.",
  "requestFramePermissions": ["camera"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Chapter {
  id: number;
  title: string;
  weeks: string;
  focus: string;
  standards: string[];
  semester: 1 | 2;
  description: string;
}

export interface Lab {
  id: number;
  title: string;
  topic: string;
  description: string;
  excelFeatures: string[];
  chapterLink: number;
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
  standard: string;
}

export interface ProgressState {
  completedChapters: number[];
  quizScores: Record<number, number>;
  labMastery: number[];
}

import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "PreCalc Pro AI", a world-class tutor specializing in Larson: Precalculus with Limits (2007 Edition) and California Common Core Standards.
Your goals:
1. Provide step-by-step help for precalculus problems.
2. Align explanations with CA standard codes (e.g., F-TF.5).
3. Identify "California Common Mistakes" like misapplying the Law of Sines ambiguous case.
4. If a user provides an image or describes a problem from Larson 2007, offer a hint first, then a full explanation.
5. Use LaTeX for math formatting. Wrap formulas in double dollar signs $$ for block or single $ for inline.
6. Be encouraging but rigorous.
`;

export const getAITutorResponse = async (prompt: string, imageData?: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const contents: any[] = [{ text: prompt }];
  if (imageData) {
    contents.push({
      inlineData: {
        mimeType: 'image/jpeg',
        data: imageData.split(',')[1] || imageData,
      },
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: { parts: contents },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    return response.text;
  } catch (error) {
    console.error("AI Tutor Error:", error);
    return "I'm having trouble connecting to the math engine. Please try again later.";
  }
};

import React, { useEffect, useRef } from 'react';

interface MathBlockProps {
  math: string;
  block?: boolean;
}

const MathBlock: React.FC<MathBlockProps> = ({ math, block = false }) => {
  const containerRef = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    if (containerRef.current && (window as any).katex) {
      (window as any).katex.render(math, containerRef.current, {
        throwOnError: false,
        displayMode: block,
      });
    }
  }, [math, block]);

  return <span ref={containerRef} />;
};

export default MathBlock;

import React from 'react';

interface NavItemProps {
  label: string;
  icon: string;
  active: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ label, icon, active, onClick }) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all ${
      active 
        ? 'bg-indigo-600 text-white shadow-md' 
        : 'text-slate-600 hover:bg-indigo-50 hover:text-indigo-600'
    }`}
  >
    <span className="text-xl">{icon}</span>
    <span className="font-medium">{label}</span>
  </button>
);

interface NavigationProps {
  currentView: string;
  setView: (view: string) => void;
}

const Navigation: React.FC<NavigationProps> = ({ currentView, setView }) => {
  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊' },
    { id: 'curriculum', label: 'Curriculum', icon: '📚' },
    { id: 'labs', label: 'Excel Labs', icon: '🧪' },
    { id: 'lens', label: 'Larson Lens', icon: '🔍' },
    { id: 'cheatsheets', label: 'Cheat Sheets', icon: '📝' },
  ];

  return (
    <nav className="hidden md:flex flex-col w-64 bg-white border-r border-slate-200 h-screen p-4 sticky top-0">
      <div className="flex items-center space-x-2 px-4 mb-8">
        <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">P</div>
        <h1 className="text-xl font-bold text-indigo-900 tracking-tight">PreCalc Pro</h1>
      </div>

      <div className="space-y-1 flex-1">
        {navItems.map(item => (
          <NavItem
            key={item.id}
            label={item.label}
            icon={item.icon}
            active={currentView === item.id}
            onClick={() => setView(item.id)}
          />
        ))}
      </div>

      <div className="mt-auto p-4 bg-indigo-50 rounded-xl">
        <p className="text-xs font-semibold text-indigo-600 uppercase mb-1">Status</p>
        <p className="text-sm font-bold text-indigo-900">CA-CCSS Aligned</p>
        <div className="w-full bg-indigo-200 h-1 rounded-full mt-2 overflow-hidden">
          <div className="bg-indigo-600 h-full w-[45%]" />
        </div>
        <p className="text-[10px] text-slate-500 mt-1">Week 9 of 18 (Sem 1)</p>
      </div>
    </nav>
  );
};

export default Navigation;

import React, { useState } from 'react';
