import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "PreCalc Pro AI", a world-class tutor specializing in Larson: Precalculus with Limits (2007 Edition) and California Common Core Standards.
Your goals:
1. Provide step-by-step help for precalculus problems.
2. Align explanations with CA standard codes (e.g., F-TF.5).
3. Identify "California Common Mistakes" like misapplying the Law of Sines ambiguous case.
4. If a user provides an image or describes a problem from Larson 2007, offer a hint first, then a full explanation.
5. Use LaTeX for math formatting. Wrap formulas in double dollar signs $$ for block or single $ for inline.
6. Be encouraging but rigorous.
`;

export const getAITutorResponse = async (prompt: string, imageData?: string) => {
  // Use named parameter and direct process.env.API_KEY access per strict guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const parts: any[] = [{ text: prompt }];
  if (imageData) {
    parts.push({
      inlineData: {
        mimeType: 'image/jpeg',
        data: imageData.split(',')[1] || imageData,
      },
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    // Access the .text property directly as it is a getter, not a method.
    return response.text;
  } catch (error) {
    console.error("AI Tutor Error:", error);
    return "I'm having trouble connecting to the math engine. Please try again later.";
  }
};

