import React, { useState } from 'react';
import Navigation from './components/Navigation';
import Dashboard from './views/Dashboard';
import CurriculumView from './views/CurriculumView';
import LensView from './views/LensView';
import ExcelLabs from './views/ExcelLabs';
import LessonDetailView from './views/LessonDetailView';
import LabDetailView from './views/LabDetailView';
import { Chapter, Lab } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('dashboard');
  const [activeLesson, setActiveLesson] = useState<Chapter | null>(null);
  const [activeLab, setActiveLab] = useState<Lab | null>(null);

  const handleLaunchLesson = (chapter: Chapter) => {
    setActiveLesson(chapter);
    setActiveLab(null);
  };

  const handleOpenLab = (lab: Lab) => {
    setActiveLab(lab);
    setActiveLesson(null);
  };

  const goBack = () => {
    setActiveLesson(null);
    setActiveLab(null);
  };

  const renderView = () => {
    if (activeLesson) {
      return <LessonDetailView chapter={activeLesson} onBack={goBack} onLensClick={() => { goBack(); setCurrentView('lens'); }} />;
    }
    if (activeLab) {
      return <LabDetailView lab={activeLab} onBack={goBack} />;
    }

    switch (currentView) {
      case 'dashboard': return <Dashboard onResume={() => handleLaunchLesson({ id: 4, title: "Trigonometry", weeks: "10–13", focus: "Radian measure, unit circle (F-TF), and graphing sine/cosine.", standards: ["F-TF.1", "F-TF.2", "F-TF.5"], semester: 1, description: "Transition from triangle geometry to the circular functions of trigonometry." })} />;
      case 'curriculum': return <CurriculumView onLaunch={handleLaunchLesson} />;
      case 'lens': return <LensView />;
      case 'labs': return <ExcelLabs onOpenLab={handleOpenLab} />;
      case 'cheatsheets': 
        return (
          <div className="flex flex-col items-center justify-center h-[70vh] text-center space-y-4">
            <div className="text-6xl">📝</div>
            <h2 className="text-2xl font-bold text-slate-900">Cheat Sheet Builder</h2>
            <p className="text-slate-500 max-w-md">Select your current Larson chapter to generate a customized California Standard Reference Sheet.</p>
            <div className="flex gap-4">
              <button 
                onClick={() => alert("Simulating PDF Generation: Standard F-TF (Trigonometric Functions) Reference Sheet created!")}
                className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-lg"
              >
                Unit Circle PDF
              </button>
              <button 
                onClick={() => alert("Simulating PDF Generation: All identities from Ch 5 added to your quick-ref sheet.")}
                className="px-6 py-3 bg-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-300 transition-colors"
              >
                Identities Sheet
              </button>
            </div>
          </div>
        );
      default: return <Dashboard onResume={() => {}} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Navigation currentView={currentView} setView={(v) => { setCurrentView(v); goBack(); }} />

      <main className="flex-1 p-4 md:p-8 lg:p-12 overflow-y-auto h-screen">
        {/* Mobile Header */}
        <div className="md:hidden flex items-center justify-between mb-8">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-xs">P</div>
            <h1 className="text-lg font-bold text-indigo-900">PreCalc Pro</h1>
          </div>
          <select 
            value={currentView} 
            onChange={(e) => { setCurrentView(e.target.value); goBack(); }}
            className="bg-white border border-slate-200 rounded-lg px-3 py-1 text-sm font-bold text-indigo-600"
          >
            <option value="dashboard">Dashboard</option>
            <option value="curriculum">Curriculum</option>
            <option value="labs">Excel Labs</option>
            <option value="lens">Larson Lens</option>
            <option value="cheatsheets">Cheat Sheets</option>
          </select>
        </div>

        <div className="max-w-7xl mx-auto">
          {renderView()}
        </div>
      </main>

      {/* Persistent CTA - Quick AI Help */}
      <button 
        onClick={() => { setCurrentView('lens'); goBack(); }}
        className="fixed bottom-6 right-6 w-14 h-14 bg-indigo-600 text-white rounded-full shadow-2xl flex items-center justify-center text-2xl hover:scale-110 transition-transform z-50 md:hidden"
      >
        🔍
      </button>
    </div>
  );
};

export default App;

