          <div>
            <h4 className="font-bold text-emerald-900 text-sm">Larson Lens Tip</h4>
            <p className="text-emerald-800 text-xs">Clearer photos of the textbook's graphs yield better analysis of asymptotes and local extrema.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

