import React, { useEffect, useRef } from 'react';

interface GraphingToolProps {
  expressions?: string[];
  className?: string;
}

const GraphingTool: React.FC<GraphingToolProps> = ({ expressions = [], className = "" }) => {
  const calculatorRef = useRef<HTMLDivElement>(null);
  const calculatorInstance = useRef<any>(null);

  useEffect(() => {
    if (calculatorRef.current && (window as any).Desmos) {
      if (!calculatorInstance.current) {
        calculatorInstance.current = (window as any).Desmos.GraphingCalculator(calculatorRef.current, {
          keypad: true,
          expressions: true,
          settingsMenu: true,
          zoomButtons: true,
          border: false
        });
      }

      // Clear existing and set new expressions
      calculatorInstance.current.setBlank();
      expressions.forEach((expr, index) => {
        calculatorInstance.current.setExpression({ id: `expr-${index}`, latex: expr });
      });
    }

    return () => {
      // Cleanup if necessary, though Desmos usually manages its own DOM
    };
  }, [expressions]);

  return (
    <div 
      ref={calculatorRef} 
      className={`w-full h-[500px] bg-white border border-slate-200 shadow-inner overflow-hidden ${className}`}
      style={{ minHeight: '400px' }}
    />
  );
};

