import React, { useEffect, useRef } from 'react';

interface GraphingToolProps {
  expressions?: string[];
  className?: string;
  chapterId?: number;
}

const GraphingTool: React.FC<GraphingToolProps> = ({ expressions = [], className = "", chapterId }) => {
  const calculatorRef = useRef<HTMLDivElement>(null);
  const calculatorInstance = useRef<any>(null);

  useEffect(() => {
    if (calculatorRef.current && (window as any).Desmos) {
      if (!calculatorInstance.current) {
        calculatorInstance.current = (window as any).Desmos.GraphingCalculator(calculatorRef.current, {
          keypad: true,
          expressions: true,
          settingsMenu: true,
          zoomButtons: true,
          border: false,
          autosize: true
        });
      }

      // Apply chapter-specific settings
      if (chapterId === 4 || chapterId === 5) {
        // Trigonometry chapters: ensure radian mode for standard unit circle functions
        calculatorInstance.current.updateSettings({
          degreeMode: false,
          showGrid: true
        });
      }

      // Clear existing and set new expressions
      calculatorInstance.current.setBlank();
      expressions.forEach((expr, index) => {
        calculatorInstance.current.setExpression({ 
          id: `expr-${index}`, 
          latex: expr,
          color: index === 0 ? '#4f46e5' : index === 1 ? '#e11d48' : '#059669',
          lineOpacity: 0.8,
          lineWidth: 3
        });
      });

      // Zoom to standard view if no bounds are specified
      if (expressions.length > 0) {
        calculatorInstance.current.setMathBounds({
          left: -10,
          right: 10,
          bottom: -10,
          top: 10
        });
      }
    }

    return () => {
      // Destructor logic if needed
    };
  }, [expressions, chapterId]);

  return (
    <div 
      ref={calculatorRef} 
      className={`w-full bg-white border border-slate-200 shadow-inner overflow-hidden ${className}`}
      style={{ minHeight: '400px' }}
    />
  );
};

export default GraphingTool;

